using System;
using System.Reflection;
using Microsoft.Agents.AI;

var asm = typeof(ChatClientAgent).Assembly;
var types = asm.GetTypes();

var targetTypes = new[] { 
    "ChatClientAgent", 
    "AgentWorker", 
    "AgentInvokeOptions",
    "AIToolAttribute",
    "AIFunctionAttribute"
};

foreach (var type in types)
{
    if (targetTypes.Contains(type.Name))
    {
        Console.WriteLine($"\n=== {type.FullName} ===");

        // Constructors
        var constructors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
        if (constructors.Length > 0)
        {
            Console.WriteLine("Constructors:");
            foreach (var ctor in constructors)
            {
                var parms = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                Console.WriteLine($"  public {type.Name}({parms})");
            }
        }

        // Methods
        var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static)
            .Where(m => !m.IsSpecialName && m.DeclaringType == type)
            .ToArray();

        if (methods.Length > 0)
        {
            Console.WriteLine("Methods:");
            foreach (var method in methods)
            {
                var parms = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                Console.WriteLine($"  public {method.ReturnType.Name} {method.Name}({parms})");
            }
        }

        // Properties
        var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance);
        if (props.Length > 0)
        {
            Console.WriteLine("Properties:");
            foreach (var prop in props)
            {
                Console.WriteLine($"  public {prop.PropertyType.Name} {prop.Name} {{ get; set; }}");
            }
        }
    }
}
