using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Tool instances ---
var notebook = new Notebook();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

// --- Build the chat client through MEAI ---
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define tools ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
        {
            return WebSearchAsync(httpClient, query);
        },
        "web_search",
        "Searches the web for the given query and returns a summary of the top results. Use this to find information about a topic."),

    AIFunctionFactory.Create(
        ([Description("Title or label for this note")] string title,
         [Description("The content to save")] string content) =>
        {
            notebook.Add(title, content);
            return $"Note saved: \"{title}\" ({content.Length} chars)";
        },
        "save_note",
        "Saves a research note with a title and content. Use this to record key findings during research."),

    AIFunctionFactory.Create(
        () =>
        {
            if (notebook.Notes.Count == 0)
                return "No notes saved yet.";

            var sb = new StringBuilder();
            for (int i = 0; i < notebook.Notes.Count; i++)
            {
                var (title, content) = notebook.Notes[i];
                sb.AppendLine($"[{i + 1}] {title}");
                sb.AppendLine(content);
                sb.AppendLine();
            }
            return sb.ToString();
        },
        "read_notes",
        "Reads all previously saved research notes. Use this to review what you've learned so far before writing a summary."),
};

// --- Create the agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to thoroughly research a topic the user provides.

        Follow this workflow:
        1. Break the topic into 2-3 specific search queries.
        2. For each query, use the web_search tool to find information.
        3. After each search, use save_note to record the key findings with a descriptive title.
        4. After completing all searches, use read_notes to review everything you've gathered.
        5. Finally, write a comprehensive summary that synthesizes all your findings.

        Be thorough but concise. Cite specific facts and data points you discover.
        """,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking notes.",
    tools: tools);

// --- Get the research topic ---
string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? "latest advances in quantum computing";
}

Console.WriteLine();
Console.WriteLine($"🔍 Researching: {topic}");
Console.WriteLine(new string('─', 60));

// --- Run the agent with streaming ---
var runOptions = new ChatClientAgentRunOptions(
    new ChatOptions { Temperature = 0f, MaxOutputTokens = 4096 });

await foreach (var update in agent.RunStreamingAsync(
    [new ChatMessage(ChatRole.User, $"Research this topic thoroughly: {topic}")],
    session: null,
    runOptions))
{
    if (update.Text is { Length: > 0 } text)
    {
        Console.Write(text);
    }
}

Console.WriteLine();
Console.WriteLine(new string('─', 60));

// --- Print saved notes ---
if (notebook.Notes.Count > 0)
{
    Console.WriteLine($"\n📝 {notebook.Notes.Count} research note(s) saved during this session.");
}

// --- Helper: web search via DuckDuckGo lite ---
static async Task<string> WebSearchAsync(HttpClient http, string query)
{
    try
    {
        var encoded = WebUtility.UrlEncode(query);
        var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";
        var response = await http.GetStringAsync(url);

        // Extract text snippets from the HTML results
        var cleaned = StripHtml(response);

        // Return a reasonable chunk of results
        const int maxLen = 3000;
        if (cleaned.Length > maxLen)
            cleaned = cleaned[..maxLen] + "\n... (results truncated)";

        return string.IsNullOrWhiteSpace(cleaned)
            ? "No results found for this query."
            : cleaned;
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

static string StripHtml(string html)
{
    // Remove script/style blocks
    var noScripts = Regex.Replace(html, @"<(script|style)[^>]*>[\s\S]*?</\1>", " ", RegexOptions.IgnoreCase);
    // Replace tags with spaces
    var noTags = Regex.Replace(noScripts, @"<[^>]+>", " ");
    // Decode entities
    var decoded = WebUtility.HtmlDecode(noTags);
    // Collapse whitespace
    var collapsed = Regex.Replace(decoded, @"\s+", " ").Trim();
    return collapsed;
}

// --- Notebook class ---
sealed class Notebook
{
    public List<(string Title, string Content)> Notes { get; } = [];

    public void Add(string title, string content)
    {
        Notes.Add((title, content));
        Console.WriteLine($"  📌 Note saved: {title}");
    }
}

